    if line.startswith('>'):
        name=line[1:]; seqs[name]=''
    else: seqs[name]+=line.lower()
inp=seqs['input']; out=seqs['output']
# find all p where out = inp[:p]+INS+inp[p:]
L=len(out)-len(inp)  #39
sols=[]
for p in range(len(inp)+1):
    if inp[:p]+out[p:p+L]+inp[p:]==out:
        sols.append((p,out[p:p+L]))
for s in sols: print(s)
EOF

